FUNCTION FullAdder(A, B, Cin)
  // Compute Sum using XOR of all three inputs
  Sum = A XOR B XOR Cin

  // Compute Carry using majority function
  Carry = (A AND B) OR (B AND Cin) OR (A AND Cin)

  RETURN (Sum, Carry)
END FUNCTION

// Example: A=1, B=1, Cin=1
// Sum = 1 XOR 1 XOR 1 = 1
// Carry = (1 AND 1) OR (1 AND 1) OR (1 AND 1) = 1

#include <stdio.h>

void carry_lookahead_4bit(int A, int B, int *result, int *carry_out) {
    // Extract individual bits
    int a[4], b[4];
    for (int i = 0; i < 4; i++) {
        a[i] = (A >> i) & 1;
        b[i] = (B >> i) & 1;
    }

    // Calculate Generate and Propagate for each stage
    int G[4], P[4];
    for (int i = 0; i < 4; i++) {
        G[i] = a[i] & b[i];           // Generate: carry out if both 1
        P[i] = a[i] ^ b[i];           // Propagate: carry in becomes carry out
    }

    // Calculate carries in parallel (look-ahead)
    int C[5];                        // C[0] is input carry
    C[0] = 0;                        // Assume no initial carry
    C[1] = G[0] | (P[0] & C[0]);
    C[2] = G[1] | (P[1] & G[0]) | (P[1] & P[0] & C[0]);
    C[3] = G[2] | (P[2] & G[1]) | (P[2] & P[1] & G[0]) | (P[2] & P[1] & P[0] & C[0]);
    C[4] = G[3] | (P[3] & G[2]) | (P[3] & P[2] & G[1]) | (P[3] & P[2] & P[1] & G[0]);

    // Calculate sum bits
    int sum = 0;
    for (int i = 0; i < 4; i++) {
        int s = P[i] ^ C[i];
        sum |= (s << i);
    }

    *result = sum;
    *carry_out = C[4];
}

int main() {
    int result, carry;
    carry_lookahead_4bit(5, 8, &result, &carry);
    printf("5 + 8 = %d, Carry = %d\n", result, carry);
    return 0;
}
